	"html/template"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	keyword := r.URL.Query().Get("keyword")

	t, err := template.New("searchResult").Parse(`
        <!DOCTYPE html>
        <html>
        <head>
            <title>Product Search</title>
        </head>
        <body>
            <h2>Search Results: {{.Keyword}}</h2>
            <p>Product results will be displayed here.</p>
        </body>
        </html>
    `)

	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	if err := t.Execute(w, struct{ Keyword string }{Keyword: keyword}); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}

