func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract and sanitize search keyword from query parameters
	keyword := html.EscapeString(r.URL.Query().Get("keyword"))

	// Log search for analytics (simple example)
